#include <bits/stdc++.h>
using namespace std;

const int N = 10;
vector<int> adj[N]; // adjacency list
vector<bool> vis(N, 0); // visited array, initially all nodes are not visited

void bfs(int v) { // Vertex v is the source
    queue<int> q;
    q.push(v); // Push the source vertex into the queue

    while(!q.empty()) { // Run till queue is not empty
        int u = q.front();
        q.pop();

        if(vis[u]) { // If the vertex is already processed, continue
            continue;
        }

        vis[u] = 1; // Set the node as visited

        cout << "Currently Traversing Vertex in BFS: " << u << "\n";

        for(auto x: adj[u]) {
            // Push the vertex into the queue to be processed
            q.push(x);
        }
    }   
}

void dfs(int v) { 
    if(vis[v]) {
        return;
    }
    cout << "Currently Traversing Vertex in DFS: " << v << "\n"; 
    vis[v] = 1; 
    for(auto u: adj[v]) { 
        dfs(u); 
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        // Reset visited array and adjacency list
        for (int i = 0; i < N; i++) {
            vis[i] = 0;
            adj[i].clear();
        }
        int E;
        cin >> E;
        for (int i = 0; i < E; i++) {
            int src, dest;
            cin >> src >> dest;
            adj[src].push_back(dest);
            adj[dest].push_back(src);
        }
        bfs(1); // Start bfs from node 1
        cout << "\n";
        // Reset visited array
        for (int i = 0; i < N; i++) vis[i] = 0;
        dfs(1); // Start dfs from node 1
        cout << "\n";
    }
