import java.util.*;
import java.io.*;

class Main {
    static int N = 10;
    static List<Integer>[] adj = new ArrayList[N];
    static boolean[] vis = new boolean[N];

    public static void bfs(int v) {
        Queue<Integer> queue = new LinkedList<>();
        queue.add(v); // Push the source vertex into the queue

        while (!queue.isEmpty()) { // Run until the queue is empty
            int u = queue.poll();

            if (vis[u]) { // If the vertex is already processed, continue
                continue;
            }

            vis[u] = true; // Set the node as visited

            System.out.println("Currently Traversing Vertex in BFS: " + u);

            for (int x : adj[u]) {
                // Push the vertex into the queue to be processed
                queue.add(x);
            }
        }
    }

    public static void dfs(int v) {
        if (vis[v]) {
            return;
        }
        System.out.println("Currently Traversing Vertex in DFS: " + v);
        vis[v] = true;
        for (int u : adj[v]) {
            dfs(u);
        }
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine());
        for(int i=0;i<N;i++)adj[i]=new ArrayList<>();
        while (T-- > 0) {
            // Reset visited array and adjacency list
            for (int i = 0; i < N; i++) {
                vis[i] = false;
            }
            int E = Integer.parseInt(br.readLine());
            for (int i = 0; i < E; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                int src = Integer.parseInt(st.nextToken());
                int dest = Integer.parseInt(st.nextToken());
                adj[src].add(dest);
                adj[dest].add(src);
            }
            bfs(1); // Start bfs from node 1
            System.out.println();
            // Reset visited array
            for (int i = 0; i < N; i++) vis[i] = false;
            dfs(1); // Start dfs from node 1
            System.out.println();
        }
    }
}

